      "keystrokes": "which git sshd && ls -la /git/server/\n",
      "duration": 0.1
    },
    {
      "keystrokes": "cat > /git/server/hooks/post-receive <<'EOF'\n#!/bin/bash\ngit --work-tree=/var/www/html --git-dir=/git/server checkout -f\nEOF\nchmod +x /git/server/hooks/post-receive\ncat /git/server/hooks/post-receive\n",
      "duration": 0.1
    },
    {
      "keystrokes": "mkdir -p /run/sshd && /usr/sbin/sshd\n",
      "duration": 1.0
